# Building a simple port scanner with multiple functions

def validate_ip(ip_address):
    """Check if IP address format is valid (simplified check)."""
    parts = ip_address.split(".")
    if len(parts) != 4:
        return False
    for part in parts:
        if not part.isdigit() or int(part) > 255:
            return False
    return True

def scan_single_port(ip, port):
    """Scan one port and return status."""
    # In real scanner, attempt socket connection here
    if port in [22, 80, 443]:  # Simulate some open ports
        return {"port": port, "status": "open"}
    else:
        return {"port": port, "status": "closed"}

def scan_port_range(ip, start_port, end_port):
    """Scan multiple ports and collect results."""
    if not validate_ip(ip):
        return {"error": "Invalid IP address"}

    results = []
    print(f"Scanning {ip} ports {start_port}-{end_port}...")

    for port in range(start_port, end_port + 1):
        result = scan_single_port(ip, port)
        if result["status"] == "open":
            results.append(result)

    return results

def generate_report(scan_results):
    """Create a summary report of scan findings."""
    if "error" in scan_results:
        print(f"Scan Error: {scan_results['error']}")
        return

    print("\n=== Scan Report ===")
    print(f"Open ports found: {len(scan_results)}")
    for result in scan_results:
        print(f"  Port {result['port']}: {result['status']}")
    print("===================\n")

