def check_port_service(port_number, protocol="TCP"):
    """
    Identify the common service running on a given port.

    Parameters:
        port_number (int): The port number to check (1-65535)
        protocol (str): The protocol type, either 'TCP' or 'UDP' (default: 'TCP')

    Returns:
        str: The name of the service typically running on this port,
             or 'Unknown' if not recognized

    Examples:
        >>> check_port_service(22)
        'SSH'
        >>> check_port_service(53, protocol="UDP")
        'DNS'
    """
    common_tcp_ports = {
        22: "SSH",
        80: "HTTP",
        443: "HTTPS",
        3389: "RDP"
    }

    common_udp_ports = {
        53: "DNS",
        161: "SNMP"
    }

    if protocol == "TCP":
        return common_tcp_ports.get(port_number, "Unknown")
    elif protocol == "UDP":
        return common_udp_ports.get(port_number, "Unknown")
    else:
        return "Invalid protocol"

