# Defensive log parsing with error handling
def parse_security_log_line(line):
    """Safely parse a security log line with validation."""
    try:
        fields = line.strip().split()

        # Validate expected number of fields
        if len(fields) < 5:
            return {"error": "Insufficient fields", "line": line}

        # Extract and validate fields
        ip = fields[0]
        timestamp = fields[1]
        method = fields[2]
        url = fields[3]
        status = fields[4]

        # Validate IP format (basic check)
        ip_parts = ip.split(".")
        if len(ip_parts) != 4:
            return {"error": "Invalid IP format", "line": line}

        # Validate status code is numeric
        try:
            status_code = int(status)
        except ValueError:
            return {"error": "Invalid status code", "line": line}

        return {
            "ip": ip,
            "timestamp": timestamp,
            "method": method,
            "url": url,
            "status": status_code,
            "error": None
        }

    except Exception as e:
        return {"error": f"Parsing failed: {str(e)}", "line": line}

