# Regex patterns for detecting common attacks

def detect_sql_injection(input_string):
    """Detect potential SQL injection attempts."""
    sql_patterns = [
        r"('|(\-\-)|(;)|(\|\|)|(\*))",  # SQL special characters
        r"\b(SELECT|UNION|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER)\b",  # SQL keywords
        r"\bOR\s+\d+\s*=\s*\d+",  # OR 1=1 pattern
        r"';\s*DROP\s+TABLE"  # Classic drop table
    ]

    for pattern in sql_patterns:
        if re.search(pattern, input_string, re.IGNORECASE):
            return True, f"Matched pattern: {pattern}"
    return False, "Clean"

def detect_command_injection(input_string):
    """Detect potential command injection attempts."""
    cmd_patterns = [
        r"[;&|`$(){}\[\]]"  ,  # Shell special characters
        r"\.\./",  # Path traversal
        r"\b(cat|ls|rm|wget|curl|nc|bash|sh)\b"  # Common commands
    ]

    for pattern in cmd_patterns:
        if re.search(pattern, input_string, re.IGNORECASE):
            return True, f"Matched pattern: {pattern}"
    return False, "Clean"

def detect_xss_attempt(input_string):
    """Detect potential XSS attempts."""
    xss_patterns = [
        r"<script[^>]*>.*?</script>",  # Script tags
        r"javascript:",  # JavaScript protocol
        r"on\w+\s*=\s*["']",  # Event handlers
        r"<iframe"  # Iframe injection
    ]

    for pattern in xss_patterns:
        if re.search(pattern, input_string, re.IGNORECASE):
            return True, f"Matched pattern: {pattern}"
    return False, "Clean"

